function i(t,a="YYYY-MM-DD HH:mm:ss"){if(!t)return"-";const e=new Date(t);if(isNaN(e.getTime()))return"-";const r=e.getFullYear(),n=String(e.getMonth()+1).padStart(2,"0"),s=String(e.getDate()).padStart(2,"0"),o=String(e.getHours()).padStart(2,"0"),c=String(e.getMinutes()).padStart(2,"0"),p=String(e.getSeconds()).padStart(2,"0");return a.replace("YYYY",r).replace("MM",n).replace("DD",s).replace("HH",o).replace("mm",c).replace("ss",p)}function u(t,a="YYYY-MM-DD HH:mm:ss"){return i(t,a)}function m(t){return{create:"创建",update:"更新",delete:"删除",allocate:"分配",release:"回收"}[t]||t}function g(t){return{ip:"IP地址",device:"设备",segment:"网段",user:"用户"}[t]||t}export{m as a,g as b,u as c,i as f};
